import requests
import json

KONG_ADMIN_URL = "http://localhost:8001"

def create_service(service_name, host, port, path="/"):
    """Create a service in Kong"""
    service_data = {
        "name": service_name,
        "host": host,
        "port": port,
        "path": path
    }
    
    response = requests.post(f"{KONG_ADMIN_URL}/services", json=service_data)
    return response.json()

def create_route(service_id, hosts, paths):
    """Create a route for a service"""
    route_data = {
        "service": {"id": service_id},
        "hosts": hosts,
        "paths": paths
    }
    
    response = requests.post(f"{KONG_ADMIN_URL}/routes", json=route_data)
    return response.json()

def create_upstream(upstream_name, algorithm="round-robin"):
    """Create an upstream in Kong"""
    upstream_data = {
        "name": upstream_name,
        "algorithm": algorithm
    }
    
    response = requests.post(f"{KONG_ADMIN_URL}/upstreams", json=upstream_data)
    return response.json()

def create_target(upstream_id, target, port=80):
    """Create a target for an upstream"""
    target_data = {
        "target": f"{target}:{port}",
        "upstream": {"id": upstream_id}
    }
    
    response = requests.post(f"{KONG_ADMIN_URL}/upstreams/{upstream_id}/targets", json=target_data)
    return response.json()

def delete_service(service_id):
    """Delete a service"""
    response = requests.delete(f"{KONG_ADMIN_URL}/services/{service_id}")
    return response.status_code

def delete_route(route_id):
    """Delete a route"""
    response = requests.delete(f"{KONG_ADMIN_URL}/routes/{route_id}")
    return response.status_code

def delete_upstream(upstream_id):
    """Delete an upstream"""
    response = requests.delete(f"{KONG_ADMIN_URL}/upstreams/{upstream_id}")
    return response.status_code

# Example usage
if __name__ == "__main__":
    # Create a service
    service = create_service("my-service", "httpbin.org", 80, "/")
    service_id = service["id"]
    
    # Create a route
    route = create_route(service_id, ["example.com"], ["/api"])
    route_id = route["id"]
    
